class StockPrice {
public:
    StockPrice() {
        latestTimestamp = 0;
    }

    void update(int timestamp, int price) {
        if (timestamp > latestTimestamp) {
            latestTimestamp = timestamp;
        }
        auto it = priceMap.find(timestamp);
        if (it != priceMap.end()) {
            int oldPrice = it->second;
            countMap[oldPrice]--;
            if (countMap[oldPrice] == 0) {
                countMap.erase(oldPrice);
            }
        }
        priceMap[timestamp] = price;
        countMap[price]++;
    }

    int current() {
        return priceMap[latestTimestamp];
    }

    int maximum() {
        return countMap.rbegin()->first;
    }

    int minimum() {
        return countMap.begin()->first;
    }

private:
    int latestTimestamp;
    unordered_map<int, int> priceMap;
    map<int, int> countMap;
};

